var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"큿.......","JPN":"くっ……","ENG":"Kgh...","TWN":"嘖……"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"빈틈을 보여줘도, 집요하게 방어만 하는군요.","JPN":"隙を見せてやっても頑なに防御に徹するんですね。","ENG":"Even when I leave openings, you keep stubbornly focusing only on defense.","TWN":"就算露出破綻，也只是一味防守啊。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하... 그 빈틈으로 당신을 끝낼 수 있다면 뻔한 함정이라도 들어가겠지만-","JPN":"はは……その隙を突くことであなたを倒せるなら、見え透いた罠でも喜んで嵌りますが……","ENG":"Haha... If I thought I could finish you through one of those openings, I'd step into even the most obvious trap...","TWN":"哈哈……要是能利用那個破綻了結你，就算擺明是陷阱我也會上當－"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"고작 그 정도로 당신을 죽일 수 있을 거라 생각하진 않거든요.","JPN":"たかが会心の一撃であなたを殺せるとは思いませんからね。","ENG":"But I don't believe a mere decisive strike would be enough to kill you.","TWN":"但我可不認為區區一次致命一擊，就能殺得了你。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"수 많은 세계를 부수고 그 정수를 손에 넣었으니, 목숨이 하나는 아닐 거라는 추측인가요?","JPN":"数多の世界を壊し、その精髄を手に入れた魔王であるからには……命は1つではないはず、ということですか？","ENG":"After all, you're a Demon Lord who has destroyed countless worlds and taken their essence. It wouldn't make sense for you to have only a single life, would it?","TWN":"畢竟你可是摧毀了無數世界、奪取其精髓的魔王—也就是說，你不只有一條命吧？"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"네. 그리고 늑대가 사라진 지금으로선...","JPN":"はい。それに、オオカミがいない今……","ENG":"Yes. And with the Wolf gone now...","TWN":"沒錯。而且現在那隻狼已經不在了……"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"내가 아니면 지금 널 붙들고 있을 사람이 없단 말이지.","JPN":"あなたの足止めができるのは僕しかいないから。","ENG":"There's no one left but me to hold you here.","TWN":"現在除了我以外，也沒人能牽制你了。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"subtitle","speaker":null,"text":{"KOREA":"현실시간으로 2일 전, 그라운드 원- 코핀 컴퍼니 1급 보안실.","ENG":"Two days earlier in real time. Ground One, Coffin Company, Level 1 Security Room.","TWN":"現實時間2天前，G1—科芬公司1級監控室。","DEU":"Two days earlier in real time. Ground One, Coffin Company, Level 1 Security Room.","FRA":"Two days earlier in real time. Ground One, Coffin Company, Level 1 Security Room."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"최종 연산 종료.","JPN":"最終演算終了。","ENG":"Final calculation complete.","TWN":"最終運算結束。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"시뮬레이션 결과- 전멸.","JPN":"シミュレーション結果、全滅。","ENG":"Simulation result... Total annihilation.","TWN":"模擬結果—全滅。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"...35번 분기에서 플랜B를 채택하면 결과는 어떻게 바뀌지?","JPN":"……35番分岐でプランBを選択した場合、結果はどう変わる？","ENG":"...What happens if we adopt Plan B at branch 35?","TWN":"……如果在第35個分支採用B計畫，結果會怎麼改變？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"실질적인 변화는 관측되지 않음. 결과는 실패, 전원 전멸입니다.","JPN":"実質的な変化は観測されず、結果は失敗。全滅です。","ENG":"No meaningful change observed. Result is failure. Total annihilation.","TWN":"未觀測到實質變化。結果仍為失敗，全員全滅。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"Bo 변수군을 제거하고, 이번엔 Ri-6773 변수를 추가해 시뮬레이션 해보지.","JPN":"Bo変数群を排除し、今回はRi-6773変数を追加してシミュレーションを行おう。","ENG":"Remove the Bo variable group and run the simulation again with the Ri-6773 variable added this time.","TWN":"移除Bo變數群，這次加入Ri-6773變數再進行模擬。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"아빠, 괜찮아?","JPN":"パパ、大丈夫？","ENG":"Daddy, are you okay?","TWN":"爸爸，你還好嗎？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"병원에 다녀온 뒤로 아직 잠도 안 잤잖아.","JPN":"病院から帰ってきてから全然寝てないよ。","ENG":"You haven't slept at all since coming back from the hospital.","TWN":"你從醫院回來後都沒睡覺。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"난 괜찮단다. 시험을 코앞에 두고 벼락치기를 할 땐 원래, 졸린 줄도 모르거든.","JPN":"私は大丈夫だ。テスト直前に一夜漬けをする時は眠けもなくなるものさ。","ENG":"I'm fine. When you're cramming right before an exam, you don't even notice how sleepy you are.","TWN":"我沒事。考試前臨時抱佛腳的時候，本來就不會覺得累。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"하이브 컨트롤은 평범한 계산기가 아니야.","JPN":"ハイブコントロールはただの計算機じゃないから。","ENG":"Hive Control isn't just an ordinary calculator.","TWN":"巢穴控制系統可不是普通的計算機。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"인과율 연산을 할 때마다 아빠가 괴로워하는 게 느껴져.","JPN":"因果律の演算をするたびに、パパが苦しむのが分かるんだよ。","ENG":"Every time you run causality calculations, I can feel how much it hurts you.","TWN":"每次進行因果運算時，我都能感覺到在折磨爸爸。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하... 가상의 체험이라 해도, 그 체험을 겪는 정신은 가상이 아니니까.","JPN":"はは……仮想の体験とはいえ、その体験をする精神は本物だからね。","ENG":"Haha... Even if it's a simulated experience, the mind that goes through it is real.","TWN":"哈哈……就算只是虛擬體驗，精神上的體驗卻是真實的。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 이번 계획은 무슨 수를 써서라도 실패해선 안돼.","JPN":"だが、今回の計算にすべてをかけないといけないんだ。","ENG":"But everything has to be staked on this calculation.","TWN":"但這次的計算，必須賭上一切。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지금까지 우리가 이루어낸 모든 기적의 가치가... 여기에 달려있단다.","JPN":"今まで我々が生み出したすべての奇跡の価値が……ここにかかっているからね。","ENG":"The value of every miracle we've created so far... depends on this.","TWN":"我們至今創造的所有奇蹟價值……都押在這裡了。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"...응. 알고 있어.","JPN":"……うん、分かってる。","ENG":"...Yeah. I know.","TWN":"……嗯，我知道。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"그럼 나도 도울게. 인과 상수 중에 빠진 게 있을지도 모르니 다시 살펴보는 거야.","JPN":"じゃあ私も手伝う。因果定数の中で抜けがあるかもしれないから、もう一度見直すよ。","ENG":"Then I'll help too. There might be a missing causality constant, so I'll check again.","TWN":"那我也來幫忙吧。說不定因果常數裡還有漏掉的部分，我再檢查一次。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래주면 고맙겠구나.","JPN":"そうしてくれると助かる。","ENG":"Thank you. I appreciate that.","TWN":"那就拜託你了。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"으앗?! 지진이야!","JPN":"わっ！？　地震！","ENG":"Whoa?! An earthquake!","TWN":"嗚哇？！地震！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"그라운드 원으로부터... 신성 출현을 관측.","JPN":"グラウンド・ワンより……神聖出現を観測。","ENG":"Divinity detected... Emerging from Ground One.","TWN":"G1……觀測到神性出現。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"신성? 아빠가 말하던 마왕일지도 몰라! 내가 혼내줄까?","JPN":"神聖？　パパが言ってた魔王かもしれない！　やっつけてあげようか？","ENG":"Divinity? It might be the Demon Lord you mentioned, Daddy! Should I go deal with it?","TWN":"神性？說不定是爸爸說的那個魔王！要我去教訓她嗎？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};